// Mock rooms data
export const ROOMS = [
  {
    id: 1, name: "The Horizon Suite", type: "Suite", price: 4200, capacity: 2,
    amenities: ["King Bed", "Sea View", "Jacuzzi", "Mini Bar"], image: "🌅",
  },
  {
    id: 2, name: "Executive Chamber", type: "Executive", price: 2800, capacity: 1,
    amenities: ["Work Desk", "City View", "Fast WiFi", "Coffee Machine"], image: "🏙️",
  },
  {
    id: 3, name: "Garden Retreat", type: "Deluxe", price: 1900, capacity: 2,
    amenities: ["Garden View", "Balcony", "Twin Beds", "Bathtub"], image: "🌿",
  },
  {
    id: 4, name: "Penthouse Loft", type: "Penthouse", price: 8500, capacity: 4,
    amenities: ["Rooftop Access", "Private Pool", "Butler", "360° View"], image: "🔭",
  },
  {
    id: 5, name: "Cozy Standard", type: "Standard", price: 950, capacity: 1,
    amenities: ["Queen Bed", "TV", "AC", "WiFi"], image: "🛏️",
  },
  {
    id: 6, name: "Family Villa", type: "Villa", price: 6100, capacity: 6,
    amenities: ["3 Bedrooms", "Private Garden", "Kitchen", "Pool"], image: "🏡",
  },
];

// Simulate network delay
const delay = (ms) => new Promise((res) => setTimeout(res, ms));

// Mock login API
export const loginAPI = async (email, password) => {
  await delay(1200);
  if (email === "demo@hotel.com" && password === "demo123") {
    return { success: true, user: { name: "Arjun Mehta", email } };
  }
  throw new Error("Invalid credentials. Please try again.");
};

// Mock availability check
export const checkAvailabilityAPI = async (roomId, checkIn, checkOut, existingBookings) => {
  await delay(900);
  const conflict = existingBookings.some(
    (b) =>
      b.roomId === roomId &&
      !(checkOut <= b.checkIn || checkIn >= b.checkOut)
  );
  return { available: !conflict };
};

// Mock confirm booking
export const confirmBookingAPI = async (bookingData) => {
  await delay(800);
  return { success: true, bookingId: `BK-${Date.now()}` };
};
